mapper.select:
--         as需要对应result的column
SELECT
    DATE (m.send_at) AS sendAt, m.from_name AS userName, COUNT (m.id) AS messageCount
FROM message m
WHERE m.send_at BETWEEN #{minus}
  AND #{now}
GROUP BY DATE (m.send_at), m.from_name
ORDER BY sendAt ASC, messageCount DESC;

SELECT
    DATE (send_at) AS sendAt, COUNT (*) AS messageCount, COUNT (DISTINCT from_name) AS userCount
FROM message
WHERE send_at BETWEEN #{minus}
  AND #{now}
GROUP BY DATE (send_at)
ORDER BY DATE (send_at);
